  "verses": [
    {
      "n": 41,
      "column": "left",
      "text": "Ta Dehla Atmus/ ta\nDehla Seerus/ ta Dehla Adajus."
    },
    {
      "n": 42,
      "column": "left",
      "text": "Ta Dehla Getana/ ta\nDehla Simus/ ta Dehla Si-\nmejus."
    },
    {
      "n": 43,
      "column": "left",
      "text": "Ta Dehla Jaâta/ ta\nDehla Gersona/ ta Dehla Letwja."
    },
    {
      "n": 44,
      "column": "left",
      "text": "Un winnu Brahti Mera-\nta Behrni stahweja pa kreifo\nRohku/ ar Wahrdü/ Getans Ku-\nsus Dehls/ ta Dehla Abdi/ ta\nDehla Malluka."
    },
    {
      "n": 45,
      "column": "left",
      "text": "Ta Dehla Asabijus/ ta\nDehla Amazijus/ ta Dehla Il-\nkijus."
    },
    {
      "n": 46,
      "column": "left",
      "text": "Ta Dehla Amzus/ ta\nDehla Banus/ ta Dehla Sa-\ninerus."
    },
    {
      "n": 47,
      "column": "left",
      "text": "Ta Dehla Maêlus/ ta\nDehla Musus/ ta Dehla Mera-\nra/ Lewja Dehla."
    },
    {
      "n": 48,
      "column": "left",
      "text": "Un winnu Brahti tee Le-\nwiti bija eezelti pee wiffadas Kal-\nposchanas ta Dewa Namuna\nDsihwokta."
    },
    {
      "n": 49,
      "column": "left",
      "text": "Un Aärons/ un winna\nDehli kwehpinaja us to Dedsa-\nmo-Uppuru Altari/ un us to\nKwehpja-Altari/ un bija eezelti\npee wiffa Darba tahs wiſs fweh-\ntakas Weetas/ ka tee Israêlu fa-\nlihdinatu/ pehz winnu/ ka tas\nDeewa Kalps Mohsus bij pa-\nwehlejs."
    },
    {
      "n": 50,
      "column": "left",
      "text": "Un schee bija Aärona\nBehrni: Eeleasars winna Dehls/\nta Dehls bija Pineas/ ta Dehls\nbija Abisuus."
    },
    {
      "n": 51,
      "column": "left",
      "text": "Ta Dehls bija Bukus/ ta"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Dehls bija Usus/ ta Dehls\nSerajus."
    },
    {
      "n": 52,
      "column": "right",
      "text": "Ta Dehls bija Merajo\nta Dehls bija Amarijus/\nDehls bija Afitabs."
    },
    {
      "n": 53,
      "column": "right",
      "text": "Ta Dehls bija Zadaks,\nDehls bija Akimaaž."
    },
    {
      "n": 54,
      "column": "right",
      "text": "Un schahs bija wi\nDsihwoschanas pehz wi\nMeestahm eeksch winnu Ro-\nschahm/(ar Wahrdü/) Aär-\nBehrneem to Raätteru R\ndeen/ jo ta nomeslota Teefa\nwinneem ta nahkusi."
    },
    {
      "n": 55,
      "column": "right",
      "text": "Un tee dewe teem Ce\nnu eeksch tahs Semmes Ju-\nun winna Preekich-Pilsfal\napkahrt winnu."
    },
    {
      "n": 56,
      "column": "right",
      "text": "Bet ta Pilsfahta Ti-\nmus/ un winna Zeemus dew\nRahlebam Jewuna Dehlain."
    },
    {
      "n": 57,
      "column": "right",
      "text": "Un Aärona Behr-\ndewe tee Jsglahbschanas- P\nfahtus/ Eebronu un Libnu /\nwinnu Preekich-Pilsfahtus."
    },
    {
      "n": 58,
      "column": "right",
      "text": "Un Jatern/ un Esten\nun winna Preekich-Pilsfah\nUn Jenu/ un winna Pree-\nPilsfahtus/ un Debiru/ un\nna Preekich-Pilsfahtus."
    },
    {
      "n": 59,
      "column": "right",
      "text": "Un Asanu un wi\nPreekich-Pilsfahtus/ un\nSeenefu un winna Pree-\nPilsfahtus."
    },
    {
      "n": 60,
      "column": "right",
      "text": "Un no Benjamixa\nGebu un winna Preekich-\nfahtus/ un Alemetu un w\nPreekich-Pilsfahtus/ un\ntotu un winna Preekich-"
    }
  ],
  "confidence": "high",
  "notes": ""
}
